 56→function isSupportedChatGptShareLink(urlString: string) {
 57→  let url: URL;
 58→  try {
 59→    url = new URL(urlString);
 60→  } catch {
 61→    return false;
 62→  }
 63→  return url.hostname === "chatgpt.com" && url.pathname.startsWith("/share/");
