 63→export function conversationToHandover(conversation: Conversation) {
 64→  const transcript = conversation.messages
 65→    .map((message) => {
 66→      const label = message.role.toUpperCase();
 67→      const body = message.blocks
 68→        .map((block) => {
 69→          switch (block.type) {
 70→            case "paragraph":
 71→            case "quote":
 72→              return block.text;
 73→            case "heading":
 74→              return block.text;
 75→            case "list":
 76→              return block.items.map((item) => `- ${item}`).join("\n");
 77→            case "code":
 78→              return `${block.language} code:\n${block.text}`;
 79→            case "table":
 80→              return [
 81→                block.headers.join(" | "),
 82→                ...block.rows.map((row) => row.join(" | ")),
 83→              ].join("\n");
 84→          }
 85→        })
 86→        .join("\n\n");
 87→
 88→      return `[${label}]\n${body}`;
 89→    })
 90→    .join("\n\n");
 91→
 92→  return `${transcript}\n\n[USER]\nContinue from this imported transcript and preserve the existing context and structure.`;
 93→}
