21→function readBlockFromDom(element: HTMLElement, original: Block): Block {
22→  switch (original.type) {
23→    case "paragraph":
24→      return { type: "paragraph", text: element.textContent ?? "" };
25→
26→    case "heading":
27→      return {
28→        type: "heading",
29→        level: original.level,
30→        text: element.textContent ?? "",
31→      };
32→
33→    case "quote":
34→      return { type: "quote", text: element.textContent ?? "" };
35→
36→    case "code":
37→      return {
38→        type: "code",
39→        language: original.language,
40→        text: element.textContent ?? "",
41→      };
42→
43→    case "list": {
44→      const listItems = element.querySelectorAll("li");
45→      const items = Array.from(listItems).map((li) => li.textContent ?? "");
46→      return {
47→        type: "list",
48→        ordered: original.ordered,
49→        items: items.length > 0 ? items : [element.textContent ?? ""],
50→      };
51→    }
52→
53→    case "table": {
54→      const thElements = element.querySelectorAll("th");
55→      const headers = Array.from(thElements).map((th) => th.textContent ?? "");
56→
57→      const bodyRows = element.querySelectorAll("tbody tr");
58→      const rows = Array.from(bodyRows).map((tr) => {
59→        const cells = tr.querySelectorAll("td");
60→        return Array.from(cells).map((td) => td.textContent ?? "");
61→      });
62→
63→      return { type: "table", headers, rows };
64→    }
